---
import { Image } from 'astro:assets';
import { getCollection } from 'astro:content';
import BaseHead from '../../components/BaseHead.astro';
import Footer from '../../components/Footer.astro';
import FormattedDate from '../../components/FormattedDate.astro';
import Header from '../../components/Header.astro';
import { SITE_DESCRIPTION, SITE_TITLE } from '../../consts';

const posts = (await getCollection('blog')).sort(
	(a, b) => b.data.pubDate.valueOf() - a.data.pubDate.valueOf(),
);
---

<!doctype html>
<html lang="en">
	<head>
		<BaseHead title={SITE_TITLE} description={SITE_DESCRIPTION} />
		<style>
			main {
				width: 960px;
			}
			ul {
				display: flex;
				flex-wrap: wrap;
				gap: 2rem;
				list-style-type: none;
				margin: 0;
				padding: 0;
			}
			ul li {
				width: calc(50% - 1rem);
			}
			ul li * {
				text-decoration: none;
				transition: 0.2s ease;
			}
			ul li:first-child {
				width: 100%;
				margin-bottom: 1rem;
				text-align: center;
			}
			ul li:first-child img {
				width: 100%;
			}
			ul li:first-child .title {
				font-size: 2.369rem;
			}
			ul li img {
				margin-bottom: 0.5rem;
				border-radius: 12px;
			}
			ul li a {
				display: block;
			}
			.title {
				margin: 0;
				color: rgb(var(--black));
				line-height: 1;
			}
			.date {
				margin: 0;
				color: rgb(var(--gray));
			}
			ul li a:hover h4,
			ul li a:hover .date {
				color: rgb(var(--accent));
			}
			ul a:hover img {
				box-shadow: var(--box-shadow);
			}
			@media (max-width: 720px) {
				ul {
					gap: 0.5em;
				}
				ul li {
					width: 100%;
					text-align: center;
				}
				ul li:first-child {
					margin-bottom: 0;
				}
				ul li:first-child .title {
					font-size: 1.563em;
				}
			}
		</style>
	</head>
	<body>
		<Header />
		<main>
			<section>
				<ul>
					{
						posts.map((post) => (
							<li>
								<a href={`/blog/${post.id}/`}>
									{post.data.heroImage && (
										<Image width={720} height={360} src={post.data.heroImage} alt="" />
									)}
									<h4 class="title">{post.data.title}</h4>
									<p class="date">
										<FormattedDate date={post.data.pubDate} />
									</p>
								</a>
							</li>
						))
					}
				</ul>
			</section>
		</main>
		<Footer />
	</body>
</html>

---
import Comment from '../../components/Comment.astro';
import For from '../../components/For.astro';
import Show from '../../components/Show.astro';
import Layout from '../../layouts/Layout.astro';
import fetchAPI from '../../lib/api';
import type { IComment, IStory } from '../../types.js';

const { id } = Astro.params as { id: string };

const story = (await fetchAPI(`item/${id}`)) as IStory;
---

<Layout>
	<div>
		<header>
			<a href={story.url} target="_blank">
				<h1>{story.title}</h1>
			</a>
			<Show when={story.domain}>
				<span class="host">({story.domain})</span>
			</Show>
			<p class="meta">
				{story.points} points | by
				<a href={`/users/${story.user}`}>
					{story.user}
				</a>
				&nbsp;{story.time_ago}
			</p>
		</header>
		<main>
			<p>
				{story.comments_count ? story.comments_count + ' comments' : 'No comments yet.'}
			</p>
			<ul class="comment-children">
				<For each={story.comments}>
					{(comment: IComment) => <Comment comment={comment} />}
				</For>
			</ul>
		</main>
	</div>
</Layout>

<style>
	header {
		background-color: rgb(248 250 252);
		padding: 1.8em 2em 1em;
		box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
	}

	h1 {
		display: inline;
		font-size: 1.5em;
		margin: 0;
		margin-right: 0.5em;
	}

	.host,
	.meta,
	.host a {
		color: rgb(51 65 85);
	}

	.meta a {
		text-decoration: underline;
	}

	main {
		background-color: rgb(248 250 252);
		margin-top: 10px;
		padding: 0 2em 0.5em;
	}

	main p {
		margin: 0;
		font-size: 1.1em;
		padding: 1em 0;
		position: relative;
	}

	main :global(ul) {
		list-style-type: none;
		padding: 0;
		margin: 0;
	}

	@media (max-width: 600px) {
		h1 {
			font-size: 1.25em;
		}
	}

	ul :global(ul) {
		margin-left: 1.5em;
	}
</style>

---
import CartFlyout from '../components/CartFlyout';
import CartFlyoutToggle from '../components/CartFlyoutToggle';
import { withBase } from '../utils';

interface Props {
	title: string;
}

const { title } = Astro.props;
---

<!doctype html>
<html lang="en">
	<head>
		<meta charset="UTF-8" />
		<meta name="viewport" content="width=device-width" />
		<meta name="generator" content={Astro.generator} />
		<link rel="icon" type="image/svg+xml" href={withBase('/favicon.svg')} />
		<link rel="icon" href={withBase('/favicon.ico')} />
		<title>{title}</title>
	</head>
	<body>
		<header>
			<nav>
				<a href={withBase('/')} class="nav-header">
					<span style="color: var(--astro-blue)">Astro</span> storefront
				</a>
				<CartFlyoutToggle client:load />
			</nav>
		</header>
		<slot />
		<CartFlyout client:load />
	</body>
</html>

<style is:global>
	:root {
		--font-family: system-ui, sans-serif;
		--font-size-base: clamp(1rem, 0.34vw + 0.91rem, 1.19rem);
		--font-size-lg: clamp(1.2rem, 0.7vw + 1.2rem, 1.5rem);
		--font-size-xl: clamp(2rem, 1.75vw + 1.35rem, 2.75rem);

		--color-text: hsl(12, 5%, 4%);
		--color-bg: hsl(17, 20%, 97%);
		--color-bg-2: hsl(17, 20%, 94%);
		--color-bg-3: hsl(17, 20%, 88%);
		--astro-blue: #4f39fa;
		--astro-pink: #da62c4;

		--content-max-width: 90ch;
		--nav-height: clamp(2.44rem, 2.38vw + 1.85rem, 3.75rem);
	}

	h1 {
		font-size: var(--font-size-xl);
	}

	button {
		border: none;
		color: var(--astro-blue);
		border: 2px solid var(--astro-blue);
		transition:
			color 0.2s,
			background-color 0.2s;
		background-color: transparent;
		padding: 0.4rem 0.8rem;
		border-radius: 0.4rem;
		font-family: var(--font-family);
		font-size: var(--font-size-base);
		font-weight: bold;
		cursor: pointer;
	}

	button:hover {
		background-color: var(--astro-blue);
		color: white;
	}
</style>

<style>
	html {
		font-family: var(--font-family);
		font-size: var(--font-size-base);
		color: var(--color-text);
		background-color: var(--color-bg);
	}

	body {
		margin: 0;
	}

	header {
		background: var(--color-bg-2);
	}

	nav {
		max-width: var(--content-max-width);
		height: var(--nav-height);
		margin: auto;
		padding-inline: 1rem;
		display: flex;
		justify-content: space-between;
		align-items: center;
	}

	.nav-header,
	.nav-header:visited {
		font-size: var(--font-size-base);
		font-weight: bold;
		color: inherit;
		text-decoration: none;
	}
</style>

