---
import For from '../components/For.astro';
import Show from '../components/Show.astro';
import Story from '../components/Story.astro';
import Layout from '../layouts/Layout.astro';
import fetchAPI from '../lib/api';
import type { IStory } from '../types.js';

const mapStories = {
	top: 'news',
	new: 'newest',
	show: 'show',
	ask: 'ask',
	job: 'jobs',
};

function safeParseInt(value: any, fallback: number) {
	try {
		return Number.parseInt(value) || fallback;
	} catch {
		return fallback;
	}
}

const page = safeParseInt(Astro.url.searchParams.get('page'), 1);
const type =
	Astro.params.stories && Astro.params.stories in mapStories
		? (Astro.params.stories.toString() as keyof typeof mapStories)
		: 'top';

const stories = (await fetchAPI(`${mapStories[type]}?page=${page}`)) as IStory[];
---

<Layout>
	<section>
		<nav aria-labelledby="current-page">
			<Show when={page > 1}>
				<a href={`/${type}?page=${page - 1}`} aria-label="Previous Page"> &lt; prev</a>
				<span slot="fallback" aria-disabled="true"> &lt; prev</span>
			</Show>
			<span id="current-page">page {page}</span>
			<Show when={stories?.length >= 29}>
				<a href={`/${type}?page=${page + 1}`} aria-label="Next Page">more &gt;</a>
				<span slot="fallback" aria-disabled="true"> more &gt;</span>
			</Show>
		</nav>
		<main>
			<Show when={stories}>
				<ul>
					<For each={stories}>{(story: IStory) => <Story story={story} />}</For>
				</ul>
			</Show>
		</main>
	</section>
</Layout>

<style>
	section {
		padding-top: 45px;
	}

	nav,
	main {
		background-color: rgb(248 250 252);
		border-radius: 2px;
	}

	nav {
		padding: 15px 30px;
		position: fixed;
		text-align: center;
		top: 55px;
		left: 0;
		right: 0;
		z-index: 998;
		box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
	}

	nav a {
		margin: 0 1em;
	}

	[aria-disabled='true'] {
		color: rgb(71 85 105);
		margin: 0 1em;
	}

	main {
		position: absolute;
		margin: 30px 0;
		width: 100%;
	}

	ul {
		list-style-type: none;
		padding: 0;
		margin: 0;
	}

	@media (max-width: 600px) {
		main {
			margin: 10px 0;
		}
	}
</style>

---
import { oklchToHex } from './color-lib';
import { store } from './store';
import ValueSlider from './value-slider.astro';

export interface Props {
	key: keyof typeof store;
	legend: string;
	labels: Record<'pickColor' | 'hue' | 'chroma', string>;
}
const { key, legend, labels } = Astro.props;
const { hue, chroma } = store[key].get();
const initialColor = oklchToHex(52, chroma, hue);
---

<color-editor data-key={key}>
	<fieldset>
		<legend>{legend}</legend>
		<label class="color-picker">
			<span class="sr-only">{labels.pickColor}</span>
			<input type="color" value={initialColor} />
		</label>
		<div class="sliders">
			<ValueSlider label={labels.hue} storeKey={key} type="hue" />
			<ValueSlider label={labels.chroma} storeKey={key} type="chroma" />
		</div>
	</fieldset>
</color-editor>

<script>
	import { oklch, oklchToHex } from './color-lib';
	import { store } from './store';

	export class ColorEditor extends HTMLElement {
		#store = store[this.dataset.key as keyof typeof store];
		#colorInput = this.querySelector<HTMLInputElement>('input[type="color"]')!;

		constructor() {
			super();
			// Update color on user input.
			this.#store.subscribe(({ chroma, hue }) => {
				this.#colorInput.value = oklchToHex(52, chroma, hue);
			});
			this.#colorInput.addEventListener('input', (e) => {
				if (!(e.target instanceof HTMLInputElement)) return;
				const old = this.#store.get();
				const { c, h } = { ...oklch(e.target.value) };
				this.#store.set({ hue: h ?? old.hue, chroma: c ?? old.chroma });
			});
		}
	}
	customElements.define('color-editor', ColorEditor);
</script>

<style>
	fieldset {
		border: 1px solid var(--sl-color-gray-5);
		background-color: var(--sl-color-gray-7, var(--sl-color-gray-6));
		padding: 1rem;
		color: var(--sl-color-white);
	}
	legend {
		float: left;
		float: inline-start;
		font-weight: 600;
	}
	.color-picker {
		float: right;
		float: inline-end;
	}
	.sliders {
		clear: both;
	}
	input[type='color'] {
		border: 0;
		background: transparent;
		height: 2em;
		width: 3rem;
		cursor: pointer;
		--swatch-border: var(--sl-color-gray-3);
	}
	input[type='color']:hover {
		--swatch-border: var(--sl-color-gray-1);
	}
	input[type='color']::-webkit-color-swatch {
		border: 1px solid var(--swatch-border);
		border-radius: 0.5rem;
	}
	input[type='color']::-moz-color-swatch {
		border: 1px solid var(--swatch-border);
		border-radius: 0.5rem;
	}
</style>
